INSERT INTO `categoria` VALUES (1,'Circuito en Serie','Circuitos donde los componentes están conectados en cadena, uno tras otro.'),(2,'Circuito en Paralelo','Circuitos donde los componentes están conectados entre sí en paralelo.'),(3,'Circuito Mixto (Serie-Paralelo)','Circuitos que combinan configuraciones en serie y paralelo.'),(4,'Divisor de Voltaje','Circuitos que dividen un voltaje de entrada en partes más pequeñas.'),(5,'Divisor de Corriente','Circuitos que dividen una corriente de entrada en partes más pequeñas.'),(6,'Una Sola Fuente','Circuitos que utilizan una sola fuente de alimentación.'),(7,'Varias Fuentes','Circuitos que utilizan múltiples fuentes de alimentación.'),(8,'Análisis de Nodos','Método de análisis que utiliza las leyes de Corrientes de Kirchhoff para resolver circuitos.'),(9,'Análisis de Mallas','Método de análisis que utiliza las leyes de Voltaje de Kirchhoff para resolver circuitos.'),(10,'Teorema de Thévenin / Norton','Teoremas que permiten simplificar circuitos complejos en equivalentes más simples.'),(11,'Superposición','Principio que permite analizar el efecto de cada fuente de forma independiente.'),(12,'Máxima Transferencia de Potencia','Principio que establece las condiciones para transferir la máxima potencia desde una fuente a una carga.'),(13,'Corriente Directa (DC)','Circuitos que operan con corriente que fluye en una sola dirección.'),(14,'Corriente Alterna (AC)','Circuitos que operan con corriente que cambia de dirección periódicamente.'),(15,'Filtros Pasivos','Circuitos que permiten pasar ciertas frecuencias mientras atienden otras.'),(16,'Respuesta en Frecuencia / Diagramas de Bode','Análisis de cómo un circuito responde a diferentes frecuencias.'),(17,'Circuitos Transitorios','Circuitos que exhiben comportamiento cambiante en el tiempo, como los circuitos RC, RL y RLC.'),(18,'Diodos: Rectificadores','Diodos utilizados para convertir corriente alterna en corriente directa (Media onda, Onda completa)'),(19,'Diodos: Recortadores y Sujetadores','Diodos utilizados para limitar o mantener un nivel de voltaje específico en una señal.'),(20,'Amplificadores con BJT','Amplificadores que utilizan transistores bipolares para aumentar la ganancia de una señal.'),(21,'Amplificadores con FET / MOSFET','Amplificadores que utilizan transistores de efecto de campo para aumentar la ganancia de una señal.'),(22,'Fuentes de Alimentación / Regulación','Circuitos que proporcionan energía eléctrica a otros circuitos, regulando el voltaje y corriente.'),(23,'Diodos: LED','Circuito que contiene cualquier tipo y color de LED');
/*!40000 ALTER TABLE `categoria` ENABLE KEYS */;
UNLOCK TABLES;

