/*!40000 ALTER TABLE `circuito` DISABLE KEYS */;
INSERT INTO `circuito` VALUES (1,'Circuito Resistivo Mixto Básico','Circuito con 4 resistencias en configuración serie-paralelo alimentadas por una fuente DC de 12V. Ideal para practicar reducción de resistencias y divisor de voltaje.','{\"pan\": {\"x\": 0, \"y\": 0}, \"zoom\": 1}','<svg>...</svg>',1,'Básico','1. Unidades eléctricas.\n2. Ley de Ohm.\n3. Código de colores.','Fundamentos de Circuitos Eléctricos','Circuitos Eléctricos'),(2,'Fuentes de Voltaje y Corriente independientes','Circuito mixto con excitación de múltiples fuentes independientes (voltaje y corriente). Ideal para aplicar el Teorema de Superposición o Análisis de Nodos.','{\"pan\": {\"x\": 0, \"y\": 0}, \"zoom\": 1}','<svg>...</svg>',1,'Intermedio','1. Elementos Activos de circuitos eléctricos.\n2. Análisis de Nodos.\n3. Teorema de Superposición','Fundamentos de Circuitos Eléctricos','Circuitos Eléctricos'),(3,'Circuito Resistivo de 4 Mallas','Circuito complejo con 4 mallas, múltiples resistencias y dos fuentes de voltaje en diferentes ramas. Excelente para practicar Análisis de Mallas, Análisis de Nodos, y aplicar las Leyes de Kirchhoff.','{\"pan\": {\"x\": 0, \"y\": 0}, \"zoom\": 1}','<svg>...</svg>',1,'Avanzado','1.Análisis de Mallas (Leyes de Kirchhoff de Corriente y Voltaje).\n2.Análisis de Nodos.','Fundamentos de Circuitos Eléctricos','Circuitos Eléctricos'),(4,'Divisor de Voltaje','Circuito Mixto con 1 fuente de voltaje y múltiples resistencias. Excelente para practicar Ley de Ohm, Divisor de Voltajes y voltajes en cada nodo y resistencia.','{\"pan\": {\"x\": 0, \"y\": 0}, \"zoom\": 1}','<svg>...</svg>',1,'Intermedio','1.Análisis de Nodos.\n2.Divisor de Voltaje.','Análisis de Circuitos en Corriente Directa.','Circuitos Eléctricos'),(5,'Divisor de Corriente','Circuito Mixto con 1 fuente de corriente y múltiples resistencias. Excelente para practicar Ley de Ohm, Divisor de Corrientes y voltajes en cada nodo.','{\"pan\": {\"x\": 0, \"y\": 0}, \"zoom\": 1}','<svg>...</svg>',1,'Intermedio','1.Análisis de Nodos.\n2.Divisor de Corriente.','Análisis de Circuitos en Corriente Directa.','Circuitos Eléctricos'),(6,'Análisis de Mallas y Nodos','Circuito complejo con 4 mallas, múltiples resistencias y múltiples fuentes en diferentes ramas. Excelente para practicar Análisis de Mallas, Análisis de Nodos, y aplicar las Leyes de Kirchhoff.','{\"pan\": {\"x\": 0, \"y\": 0}, \"zoom\": 1}','<svg>...</svg>',1,'Avanzado','1.Análisis de Mallas (Leyes de Kirchhoff de Corriente y Voltaje).\n2.Análisis de Nodos.','Análisis de Circuitos en Corriente Directa','Circuitos Eléctricos'),(7,'Teorema de Superposición','Circuito con varias fuentes independientes (tensiones y corrientes) y varias resistencias. Ideal para practicar el Teorema de Superposición.','{\"pan\": {\"x\": 0, \"y\": 0}, \"zoom\": 1}','<svg>...</svg>',1,'Intermedio','1.Teorema de Superposición.\n2.Análisis de Mallas.\n3.Análisis de Nodos.','Análisis de Circuitos en Corriente Directa','Circuitos Eléctricos'),(8,'Teoremas de Thévenin y Norton','Circuito con varias fuentes independientes (tensiones y corrientes) y varias resistencias. Ideal para practicar los Teoremas de Thévenin y Norton.','{\"pan\": {\"x\": 0, \"y\": 0}, \"zoom\": 1}','<svg>...</svg>',1,'Intermedio','1.Teoremas de Thévenin y Norton.\n2.Teorema de Intercambio de Fuentes.','Análisis de Circuitos en Corriente Directa','Circuitos Eléctricos'),(9,'Teorema de Máxima Transferencia de Potencia','Circuito que sirve para encontrar experimentalmente el valor de RL para obtener la máxima transferencia de potencia a la carga. Compara los resultados experimentales con los cálculos teóricos basados en el teorema de Thévenin.','{\"pan\": {\"x\": 0, \"y\": 0}, \"zoom\": 1}','<svg>...</svg>',1,'Intermedio','1.Teoremas de Thévenin y Norton.\n2.Teorema de Máxima Transferencia de Potencia.','Análisis de Circuitos en Corriente Directa','Circuitos Eléctricos'),(10,'Circuito RC Básico en Corriente Alterna','Análisis de un circuito con resistencia y capacitor en AC. El capacitor introduce un desfase entre el voltaje y la corriente, creando una impedancia compleja en el sistema.','{\"pan\": {\"x\": 0, \"y\": 0}, \"zoom\": 1.0}','<svg>...</svg>',1,'Básico','Circuitos de Corriente Alterna (AC)','Análisis del Circuito en el Dominio de la Frecuencia','Circuitos Eléctricos'),(11,'Circuito RL Básico en Corriente Alterna','Análisis de un circuito con resistencia e inductor en AC. La bobina crea una reactancia inductiva que desfasa la corriente respecto al voltaje, introduciendo una impedancia compleja en el sistema.','{\"pan\": {\"x\": 0, \"y\": 0}, \"zoom\": 1.0}','<svg>...</svg>',1,'Básico','Circuitos de Corriente Alterna (AC)','Análisis del Circuito en el Dominio de la Frecuencia','Circuitos Eléctricos'),(12,'Circuito RLC en Serie en Corriente Alterna','Análisis de un circuito con resistencia, inductor y capacitor en AC. El sistema presenta una impedancia compleja que varía con la frecuencia.','{\"pan\": {\"x\": 0, \"y\": 0}, \"zoom\": 1.0}','<svg>...</svg>',1,'Intermedio','Circuitos de Corriente Alterna (AC)','Análisis del Circuito en el Dominio de la Frecuencia','Circuitos Eléctricos'),(13,'Circuito Rectificador de Media Onda','Análisis de un circuito rectificador de media onda con diodo y resistencia. El diodo permite el paso de la corriente solo durante la mitad del ciclo de la señal de entrada, produciendo una salida pulsante.','{\"pan\": {\"x\": 0, \"y\": 0}, \"zoom\": 1.0}','<svg>...</svg>',1,'Básico','Circuitos de Corriente Alterna (AC)','Dispositivos Semiconductores','Electrónica Analógica'),(14,'Circuito Regulador de Voltaje con Diodo Zener','El diodo Zener mantiene una salida de voltaje constante en una carga (RL), absorbiendo variaciones de la fuente con el diodo en polarización inversa.','{\"pan\": {\"x\": 0, \"y\": 0}, \"zoom\": 1.0}','<svg>...</svg>',1,'Básico','1.Teoría de Semiconductores.\n2.Diodo Zener','Dispositivos Semiconductores','Electrónica Analógica'),(15,'Circuito con LED verde','Circuito sencillo con una resistencia y un LED Verde para practicar el voltaje de umbral que tiene este LED.','{\"pan\": {\"x\": 0, \"y\": 0}, \"zoom\": 1.0}','<svg>...</svg>',1,'Básico','1.Teoría de Semiconductores.\n2.Diodo Emisor de Luz','Dispositivos Semiconductores','Electrónica Analógica'),(16,'Circuito Regulador Fijo 7805','Este circuito utiliza una entrada de entre 7V y 35V DC para entregar una salida constante de 5V y hasta 1.5A de corriente. Se requiere el regulador LM7805, un condensador de entrada (0.33uF) y uno de salida (0.1uF) para estabilizar la tensión y filtrar ruidos.','{\"pan\": {\"x\": 0, \"y\": 0}, \"zoom\": 1.0}','<svg>...</svg>',1,'Básico','1.Regulador de Voltaje Lineal.','Dispositivos Semiconductores','Electrónica Analógica'),(17,'Circuito BJT Polarización en emisor común','Circuito que tiene como finalidad fijar el punto de trabajo Q del transistor mientras está en su zona activa. Esto garantiza una amplificación estable de la señal y evita que el punto de operación varíe por cambios de temperatura.','{\"pan\": {\"x\": 0, \"y\": 0}, \"zoom\": 1.0}','<svg>...</svg>',1,'Intermedio','1. Transistores BJT.','Dispositivos Semiconductores','Electrónica Analógica'),(18,'Circuito Regulador Ajustable 317','Este circuito utiliza una entrada de 13V para entregar una salida ajustable desde 1.25V aprox. hasta 10V aprox. Se requiere el regulador LM317, en compañía de una resistencia variable (R2) para ajustar la salida de voltaje, una resistencia de referencia (R1) y una resistencia de carga (R3).','{\"pan\": {\"x\": 0, \"y\": 0}, \"zoom\": 1.0}','<svg>...</svg>',1,'Intermedio','1.Regulador de Voltaje Ajustable.','Dispositivos Semiconductores','Electrónica Analógica'),(19,'Circuito BJT como interruptor con fuente (AC)','Conforme la onda AC sube y cruza la barrera de los 0.7V, la unión Base-Emisor se polariza en directa y el LED (rojo) se enciende. Cuando el voltaje cae a números negativos, la unión Base-Emisor actúa como un interruptor abierto y El LED se apaga.','{\"pan\": {\"x\": 0, \"y\": 0}, \"zoom\": 1.0}','<svg>...</svg>',1,'Intermedio','1. Transistores BJT. 2. Led. 3. Saturación del BJT.','Dispositivos Semiconductores','Electrónica Analógica'),(20,'Circuito MOSFET como interruptor con fuente (AC)','En este circuito, cuando el IRFZ44N es activado por voltaje en la compuerta (Gate), requiere de 10V a 15V para saturarse completamente. Se controla con 0V (apagado) y +10V (encendido) en la compuerta.','{\"pan\": {\"x\": 0, \"y\": 0}, \"zoom\": 1.0}','<svg>...</svg>',1,'Intermedio','Dispositivos Semiconductores','1. Transistor de Efecto de Campo (FET): .\n2. Saturación del FET.','Electrónica Analógica');
/*!40000 ALTER TABLE `circuito` ENABLE KEYS */;
